package com.example.demo.controller;import com.example.demo.dto.UsuarioDTO;import com.example.demo.services.UsuarioService;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/api/usuarios") public class UsuarioController{private final UsuarioService service;public UsuarioController(UsuarioService service){this.service=service;}@GetMapping public List<UsuarioDTO> listar(){return service.listar();}@PostMapping public UsuarioDTO crear(@RequestBody UsuarioRequest r){return service.guardar(null,r.usuario(),r.password());}@PutMapping("/{id}")public UsuarioDTO editar(@PathVariable Long id,@RequestBody UsuarioRequest r){return service.guardar(id,r.usuario(),r.password());}public record UsuarioRequest(UsuarioDTO usuario,String password){}}
